INSERT INTO cats VALUES(1661,1077175817,'BAZYL','Spokojny, przyjazny do innych kotów. Do człowieka coraz bardziej się przełamuje i chce być blisko.','https://www.pk-raciborz.pl/files_tiny/schronisko/bazyl.jpg','2026-07-07 13:37:29','https://www.pk-raciborz.pl/site/index/5-schronisko.html','samiec','2024');
INSERT INTO cats VALUES(1662,1077175817,'ADAŚ','Adaś potrzebuje czasu, żeby poznać i zaufać. Gdy czuje się bezpiecznie pozwala się głaskać, jednak sam raczej nie podchodzi. Potrzebuje cierpliwego domu, znającego potrzeby kota.','https://www.pk-raciborz.pl/files_tiny/schronisko/adas1.jpg','2026-07-07 13:37:29','https://www.pk-raciborz.pl/site/index/5-schronisko.html','samiec','2025');
INSERT INTO cats VALUES(1663,1077175817,'BOLO','Bolo trafił do schroniska ze swoim bratem Bono. Oba koy były dosyć mocno wcofane. Potrzebują czasu, żeby zaufaćć ale małymi krokami przełamuja swój strach przed człowiekiem.','https://www.pk-raciborz.pl/files_tiny/schronisko/bolo.jpg','2026-07-07 13:37:29','https://www.pk-raciborz.pl/site/index/5-schronisko.html','samiec','2025');
